// Generated by GitHub Copilot
import { useEffect, useRef, useState } from 'react'
import './App.css'
import { buildApiEndpoint, createPeoplePresenceConnection } from './peoplePresence.js'

const peopleEndpointPath = '/api/people'
const editorNameStorageKey = 'people-editor-name'

/**
 * @typedef {Object} Person
 * @property {number} id
 * @property {string} name
 * @property {string} role
 * @property {string} location
 * @property {string} email
 */

/**
 * Fetches people from the ModernApi service.
 * @param {string} endpoint
 * @param {AbortSignal} signal
 * @returns {Promise<Person[]>}
 */
async function fetchPeople(endpoint, signal) {
  const response = await fetch(endpoint, {
    headers: {
      Accept: 'application/json',
    },
    signal,
  })

  if (!response.ok) {
    throw new Error(`People request failed with status ${response.status}.`)
  }

  return response.json()
}

/**
 * Reads an API error payload and returns a readable message.
 * @param {Response} response
 * @returns {Promise<string>}
 */
async function readApiError(response) {
  const payload = await response.json().catch(() => null)

  if (payload?.errors) {
    return Object.values(payload.errors).flat().join(' ')
  }

  if (payload?.title) {
    return payload.title
  }

  return `Request failed with status ${response.status}.`
}

/**
 * Persists an updated person to the ModernApi service.
 * @param {string} endpoint
 * @param {{ name: string, role: string, location: string, email: string }} person
 * @returns {Promise<Person>}
 */
async function updatePerson(endpoint, person) {
  const response = await fetch(endpoint, {
    method: 'PUT',
    headers: {
      Accept: 'application/json',
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(person),
  })

  if (!response.ok) {
    throw new Error(await readApiError(response))
  }

  return response.json()
}

/**
 * Creates an editable draft from a person record.
 * @param {Person} person
 * @returns {{ name: string, role: string, location: string, email: string }}
 */
function createPersonDraft(person) {
  return {
    name: person.name,
    role: person.role,
    location: person.location,
    email: person.email,
  }
}

/**
 * Creates a readable default editor name for the current browser tab.
 * @returns {string}
 */
function createDefaultEditorName() {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return `User ${crypto.randomUUID().slice(0, 8)}`
  }

  return `User ${Math.random().toString(36).slice(2, 10)}`
}

/**
 * Gets the editor name persisted for the current browser tab.
 * @returns {string}
 */
function getInitialEditorName() {
  if (typeof window === 'undefined') {
    return 'Anonymous user'
  }

  const storedName = window.sessionStorage.getItem(editorNameStorageKey)?.trim()

  if (storedName) {
    return storedName
  }

  const defaultName = createDefaultEditorName()
  window.sessionStorage.setItem(editorNameStorageKey, defaultName)
  return defaultName
}

/**
 * Persists the editor name for the current browser tab.
 * @param {string} editorName
 * @returns {void}
 */
function persistEditorName(editorName) {
  if (typeof window !== 'undefined') {
    window.sessionStorage.setItem(editorNameStorageKey, editorName)
  }
}

/**
 * Converts a SignalR presence payload into a person-indexed lookup.
 * @param {{ personId: number, personName: string, editors: string[] }[]} snapshot
 * @returns {Record<number, { personId: number, personName: string, editors: string[] }>}
 */
function normalizePresenceSnapshot(snapshot) {
  return snapshot.reduce((presenceByPersonId, presence) => {
    presenceByPersonId[presence.personId] = presence
    return presenceByPersonId
  }, {})
}

/**
 * Formats editor names for display on cards and summaries.
 * @param {string[]} editorNames
 * @param {string} currentEditorName
 * @returns {string}
 */
function formatEditorNames(editorNames, currentEditorName) {
  return editorNames
    .map((editorName) =>
      editorName === currentEditorName ? 'You' : editorName,
    )
    .join(', ')
}

/**
 * Formats editor names for singular or plural toast copy.
 * @param {string[]} editorNames
 * @param {string} currentEditorName
 * @returns {string}
 */
function formatToastEditorNames(editorNames, currentEditorName) {
  const formattedNames = editorNames.map((editorName) =>
    editorName === currentEditorName ? 'you' : editorName,
  )

  if (formattedNames.length <= 1) {
    return formattedNames[0] ?? ''
  }

  if (formattedNames.length === 2) {
    return `${formattedNames[0]} and ${formattedNames[1]}`
  }

  return `${formattedNames.slice(0, -1).join(', ')}, and ${formattedNames.at(-1)}`
}

/**
 * Announces the current edit state to the SignalR hub.
 * @param {import('@microsoft/signalr').HubConnection} connection
 * @param {{ id: number, name: string } | null} person
 * @param {string} editorName
 * @returns {Promise<void>}
 */
async function syncEditingPresence(connection, person, editorName) {
  if (person) {
    await connection.invoke('StartEditing', {
      personId: person.id,
      personName: person.name,
      editorName,
    })
    return
  }

  await connection.invoke('StopEditing')
}

/**
 * Renders live editing presence and lets the user set a display name.
 * @param {{
 *   editorName: string,
 *   onEditorNameChange: (event: import('react').ChangeEvent<HTMLInputElement>) => void,
 *   presenceState: string,
 *   activeEdits: { personId: number, personName: string, editors: string[] }[],
 *   currentEditorName: string,
 * }} props
 * @returns {JSX.Element}
 */
function EditingPresencePanel({
  editorName,
  onEditorNameChange,
  presenceState,
  activeEdits,
  currentEditorName,
}) {
  const connectionLabelByState = {
    connecting: 'Connecting live presence',
    connected: 'Live presence connected',
    reconnecting: 'Reconnecting live presence',
    disconnected: 'Live presence unavailable',
  }

  return (
    <section aria-labelledby="editing-presence-heading" className="presence-panel">
      <div className="presence-panel__header">
        <div>
          <p className="presence-panel__eyebrow">SignalR presence</p>
          <h2 id="editing-presence-heading">Who is editing right now</h2>
        </div>
        <div className={`presence-panel__status presence-panel__status--${presenceState}`}>
          {connectionLabelByState[presenceState] ?? connectionLabelByState.disconnected}
        </div>
      </div>

      <label className="people-field people-field--presence" htmlFor="editor-name">
        <span>Your display name</span>
        <input
          id="editor-name"
          maxLength="40"
          onChange={onEditorNameChange}
          value={editorName}
        />
      </label>

      {activeEdits.length > 0 ? (
        <ul className="presence-list" aria-label="Active editing presence">
          {activeEdits.map((presence) => (
            <li className="presence-list__item" key={presence.personId}>
              <strong>{formatEditorNames(presence.editors, currentEditorName)}</strong>
              <span> editing {presence.personName}</span>
            </li>
          ))}
        </ul>
      ) : (
        <p className="presence-panel__empty">No one is editing a person right now.</p>
      )}
    </section>
  )
}

